function-vul
int __fastcall vul(int a1)
&#123;
  int result; // eax
  char nbytes[52]; // [rsp+Ch] [rbp-34h] BYREF

  result = system(&quot;date&quot;);
  if ( a1 &lt;= 47 )
  &#123;
    read(0, &amp;nbytes[4], (unsigned int)a1);
    return (unsigned int)strncpy(buf, &amp;nbytes[4], 0x200uLL);
  &#125;
